// ===== Basic Protection Layer =====

// 1. تعطيل كليك يمين (اختياري - تقدر تشيله)
document.addEventListener("contextmenu", (e) => e.preventDefault());

// 2. منع بعض اختصارات DevTools (بدون إزعاج)
document.addEventListener("keydown", (e) => {
  if (
    e.key === "F12" ||
    (e.ctrlKey && e.shiftKey && ["I", "J", "C"].includes(e.key)) ||
    (e.ctrlKey && e.key === "U")
  ) {
    e.preventDefault();
  }
});

// 3. كشف فتح DevTools (بدون تخريب UX)
(function () {
  let devtoolsOpen = false;

  const detect = () => {
    const threshold = 160;
    const widthDiff = window.outerWidth - window.innerWidth > threshold;
    const heightDiff = window.outerHeight - window.innerHeight > threshold;

    if (widthDiff || heightDiff) {
      if (!devtoolsOpen) {
        devtoolsOpen = true;
        console.warn("DevTools detected");
        
        // تقدر تحط أكشن خفيف هنا:
        // مثلاً توقف بعض الوظائف الحساسة
        window.__DEVTOOLS_OPEN__ = true;
      }
    } else {
      devtoolsOpen = false;
      window.__DEVTOOLS_OPEN__ = false;
    }
  };

  setInterval(detect, 1000);
})();

// 4. تعطيل console.log في الإنتاج
(function () {
  const noop = () => {};
  console.log = noop;
  console.warn = noop;
  console.error = noop;
})();

// 5. حماية بسيطة ضد نسخ الكود من console
Object.defineProperty(window, "console", {
  value: console,
  writable: false,
  configurable: false
});
